var e=[{id:`L2_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`이 떨거지들이......! 선수를 방해해도 된다니까 죽일 듯이 달려들어?`,JPN:`雑魚どもが……！　選手の妨害がOKだからって殺す気で飛び掛かってくるの！？`,ENG:`Those gnats... They're supposed to interfere with the runners, not kill them!`,TWN:`你們這些小嘍囉……！雖然規則是妨礙，你們還真不要命了？`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_HATE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`그리고 왜 나만 노리는 거야! 다른 녀석들도 많은데!`,JPN:`なんで私ばっかり狙うの！　他のやつもいるのに！`,ENG:`And why are they all after me and not somebody else?`,TWN:`不過幹嘛只盯著我啊！還有那麼多人呢！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_SERIOUS`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`이건 분명 감정 섞인 공격이야! 경기 끝나고 두고 봐!`,JPN:`これは間違いなく私情が入った攻撃よ！　試合が終わったら全員まとめて覚悟しなさい！`,ENG:`This has to be personal! I'll make them pay after the game!`,TWN:`這分明是蓄意攻擊！等比賽結束要你們好看！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_BLUE`,text:{KOREA:`미, 미안해요......!`,JPN:`ご、ごめんなさい……！`,ENG:`I-I'm sorry!`,TWN:`對，對不起……！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`POLEARM_JUNIOR_NULL_BLUE`,face:`UNIT_DESPAIR`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_BLUE`,text:{KOREA:`이야앗!!`,JPN:`やああっ！！`,ENG:`Eeyaaap!`,TWN:`咿呀啊！！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`POLEARM_JUNIOR_NULL_BLUE`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`히이익-!`,JPN:`ひいいーっ！`,ENG:`Heeek!`,TWN:`（驚）咿！！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_SURPRISE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`PLAYER_SPORTS_NPC_BLUE`,text:{KOREA:`죄송합니다! 선배님!`,JPN:`ごめんなさい！　先輩！`,ENG:`I'm sorry, Naielle!`,TWN:`抱歉，前輩！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`흐히이익?!`,JPN:`ひいいいーっ！？`,ENG:`Heeek!`,TWN:`呃嘿咿咿？！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_SURPRISE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`방금 건 분명 죽었어! 맞았으면 진짜로 죽었다고!!`,JPN:`今のは確実に死ぬところだったわよ！？　リアルに当たると死ぬやつよそれ！？`,ENG:`That was a killing blow! I would have died if that hit!`,TWN:`剛才分明應該死了！打中了就是死了呀！！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`너희들! 죄송하다면서 왜 계속 머리를 노리는 거야?!`,JPN:`あんたたち！　ごめんなさいと言いながら私の頭ばかり狙うのはやめて！？`,ENG:`You! If you're so sorry, why do you keep aiming at my head?`,TWN:`你們！嘴裡說著對不起，卻一直盯著我的頭？！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`HARIM_REBBIT_SPORTS_BG`,text:{KOREA:`홍팀의 나이엘 블루스틸 선수! 선두를 달리며 마지막 바퀴에 진입합니다!`,JPN:`赤組のナイエル・ブルースチール選手！　先頭を走りながら最後の一周に入ります！`,ENG:`Naielle Bluesteel of the Red Team, on the last lap before everyone else!`,TWN:`紅隊的奈爾選手！一馬當先地進入最後一圈了！`},stage:{bg:`SS_SPORTS_02`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`HARIM_REBBIT_SPORTS_BG`,text:{KOREA:`청팀의 방해가 거세지만, 이대로 가면 1등은 확정 같아 보이네요!`,JPN:`青組の妨害が激しいものの、この調子だと1位は確定ですね！`,ENG:`The Blue Team is trying really hard to stop her, but at this rate, it's obvious she'll come in first.`,TWN:`雖然藍隊的阻礙很激烈，但不出意外，第一名應該是奈爾沒錯了！`},stage:{bg:`SS_SPORTS_02`,slots:{L:null,C:null,R:null}}},{id:`L27_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`흐, 흥! 그럼 그렇지!`,JPN:`ふ、ふん！　当たり前よ！`,ENG:`H-hmpf! I knew it!`,TWN:`呵，哼！我就說嘛！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_PRIDE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`떨거지들이 아무리 방해해 봤자 떨거지들이지!`,JPN:`雑魚はどうあがいても雑魚だから！`,ENG:`Gnats are gnats, no matter how hard they try to be something else!`,TWN:`小嘍囉們再怎麼妨礙都無濟於事！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_IDLE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`SEOYOON_ALT_SPORTS_NOBG`,text:{KOREA:`흐음, 그럼 탐색전은 끝난 것 같고......`,JPN:`ふうん、様子見はこの程度にして……`,ENG:`Hmm, I guess I'm done observing the situation.`,TWN:`哼嗯，試探性的對戰看來也差不多了……`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`SEOYOON_ALT_SPORTS_NOBG`,face:`UNIT_IDLE`},R:null}}},{id:`L31_1`,type:`dialog`,speaker:`SEOYOON_ALT_SPORTS_NOBG`,text:{KOREA:`슬슬 스퍼트를 올려 볼까?`,JPN:`そろそろスパートをかけようかな？`,ENG:`It's time to pick up the pace.`,TWN:`提升一下速度吧？`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`SEOYOON_ALT_SPORTS_NOBG`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};